var richText = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Join a young boy on a magical day with his beloved grandpa, where imagination turns everyday moments into enchanting adventures. Together, they explore a world full of wonder, sharing laughs, stories, and special memories that highlight the joy of family time. Through gentle rhymes and heartfelt scenes, this story celebrates the love between generations, reminding us how precious these shared days can be." }), /* @__PURE__ */ e("p", { children: "Written and illustrated by Fiona Rose, this delightful dual language book bursts with vibrant, magical pictures that bring the tale to life for little ones and grown-ups alike. It's perfect for sparking chats about grandparents and creating lasting bonds, making it a treasured read for families who want to cherish every moment together." })] });
var richText1 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Who says only girls can be angels? Angels can do all the things that Alfie wants to do. If he were an angel he could fly to school, sing and dance in the choir, and fly around the football pitch scoring goal after goal. Will Alfie's dreams of being an angel ever come true?" }), /* @__PURE__ */ e("p", { children: "This is a charming story in dual language about daring to do the unexpected. Alfie's inspiring individuality makes this text useful for discussing identity and independent thinking with Key Stage 1 readers.\xA0 For older children 'Alfie's Angels' is a perfect stimulus for introducing issues such as gender roles and stereotypes in the classroom." })] });
var richText2 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "In a dusty village nestled in the Arabian Desert, humble woodcutter Ali Baba discovers a secret cave brimming with glittering stolen treasure, guarded by a gang of forty sneaky thieves. When the bandits catch wind of his find and chase him down for revenge, Ali Baba must use his cleverness, a dash of luck, and help from a smart friend to turn the tables. Packed with exciting twists, clever tricks, and heart-pounding escapes, this timeless adventure will have young readers cheering for the underdog." }), /* @__PURE__ */ e("p", { children: "This enchanting dual language retelling from Mantra Lingua's 'Folktales, Myths and Legends' collection sparks imagination and fun while gently touching on ideas like fairness and bravery. Richard Holland's beautiful, colourful collages inspired by Arabic art add a splash of magic, making it a wonderful pick for families and schools to share stories from around the world and chat about right and wrong in a light-hearted way." })] });
var richText3 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Augustus the tiger has lost his smile. He sets out to find it and begins a journey that takes him all over the world through dense jungles, arid deserts, and deep oceans. By the time his journey finally comes to an end, Augustus has realised that he will never be without his smile again. " }), /* @__PURE__ */ e("p", { children: "Catherine Rayner's simple, poetic story is a mesmerising tale about finding happiness in the world around us. Perfect for story time or for encouraging independent reading, Augustus' journey will allow children to reflect on themes such as memory, happiness, and the natural world. Beautiful illustrations inspired by Asian artwork complement Rayner's simple narrative. Indeed, Augustus himself is a magnificently handsome tiger whose fiery stripes infuse the pages with warmth and energy." })] });
var richText4 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "For twelve years, Grendel, a ferocious and bloodthirsty creature, terrorises King Hrothgar's people, killing and devouring their bravest warriors. That is until one day when Beowulf, the strongest and mightiest of the Geat warriors, arrives on the Danish shores determined to defeat Grendel. When Beowulf slaughters the vicious creature, the kingdom rejoices but the celebrations do not last long. In all the excitement, the people of Hrothgar have forgotten about Grendel's keenest ally\u2026" }), /* @__PURE__ */ e("p", { children: "This gripping dual language adaptation of the Anglo-Saxon epic makes the legend of Beowulf accessible to readers of all ages. As well as offering a thrilling insight into Anglo-Saxon history, this reworking of the 8th century poem can be used to introduce readers to the study of Old English and epic poetry. Brought to life through Alan Down's powerful illustrations, Beowulf's exploits also invite discussion of heroism, myths, and legends." })] });
var richText5 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Brown bear, brown bear, what do you see? I see a red bird looking at me. Red bird, red bird, what do you see? I see a yellow duck looking at me. Follow along as a parade of colourful animals spots the next friend in line, from a purple cat to a goldfish, all leading up to a group of happy children. This catchy, rhyming tale builds excitement with each page turn, making it a joyful way for tiny tots to spot colours and name animals." }), /* @__PURE__ */ e("p", { children: "A timeless favourite for early years, this dual language book by Eric Carle bursts with bright, bold illustrations that invite little ones to join in the fun through sing-alongs and games. Perfect for circle time or cosy family reads, it's a wonderful pick for parents and teachers wanting to spark curiosity about colours and creatures in a playful, interactive way." })] });
var richText6 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "How people get around depends on where they live. You might be used to travelling by car, bike or train but in Norway Falda hitches a ride on her sister's snowmobile and in Thailand, Niran gets home on a tuk-tuk. Why do you think people use different modes of transport? Which would you most like to try?" }), /* @__PURE__ */ e("p", { children: "Mantra Lingua's Our Lives, Our World series of dual language books helps young readers to widen their horizons and to develop a tolerant worldwide perspective by introducing them to diverse cultures, traditions and lifestyles.\xA0 Simple, repetitive sentence structures and basic vocabulary make these titles useful for building verbal communication skills.\xA0 An essential cross-curricular resource for teaching EAL, Citizenship and PSHE, each title in this series includes a key words and activities section for use in the classroom." })] });
var richText7 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Meet Buri, a clever old woman heading home through the forest with a giant marrow, but a hungry tiger, greedy lion, and sly fox all want to gobble her up. With quick thinking and a sneaky plan, Buri outsmarts the tiger and lion one by one, but will her tricks work on the clever fox too? Full of fun surprises and repeating rhymes, this lively tale keeps young readers giggling as Buri makes her way safely home." }), /* @__PURE__ */ e("p", { children: "This charming dual language retelling from Mantra Lingua's World Tales collection brings a traditional Bengali story to life with vibrant illustrations and clever twists that delight kids and grown-ups. Great for sharing aloud in class or at home, it's ideal for exploring folk tales from around the world, chatting about bravery and cleverness, and discovering a bit of Indian culture together." })] });
var richText8 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "It's Diwali time, but things aren't going smoothly for little Deepak\u2014Dad forgot the sparklers, the fairy lights are broken, and after hearing the tale of Rama and Sita, Deepak is convinced the demon king Ravana is coming for him! As his family prepares for the festival of lights, Deepak's worries turn into excitement with yummy treats, sparkling decorations, and a surprise that saves the day. Join Deepak on a fun adventure that mixes modern family mishaps with the magic of Diwali." }), /* @__PURE__ */ e("p", { children: "Part of Mantra Lingua's Celebration Series, this dual language book is packed with colourful pictures, easy recipes, and fun facts to help families dive into Diwali traditions from around the world. Whether at home or in school, it's a lovely way to introduce kids to different cultures, share stories of festivals, and create happy memories with activities that bring everyone together." })] });
var richText9 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Little Red the hen has a noisy neighbour\u2014Mrs Fox, who's always hungry for roast chicken, and her sneaky son Sly is out to catch one. But in this fun twist on the classic tale, Sly and Little Red team up to trick his bossy mum, finding a clever way to feed the fox family without anyone ending up on the dinner plate. Full of laughs, teamwork, and smart ideas, this story shows how kindness and quick thinking can save the day." }), /* @__PURE__ */ e("p", { children: "This delightful dual language retelling from Mantra Lingua's 'Folktales, Myths and Legends' collection brings fresh fun to an old favourite, with lively pictures and rhymes that kids and grown-ups will adore. Perfect for families and classrooms, it's a great way to chat about being kind, working together, and seeing things from different sides, while exploring stories from around the world." })] });
var richText10 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "A girl at school is bullying Ellie but she keeps it to herself, writing about what happens in her diary. Things go from bad to worse until one day Ellie is caught stealing money from her mum and she bursts into tears and spills all to her parents. Read Ellie's diary to see how she dealt with the bullying and how she put a stop to it." }), /* @__PURE__ */ e("p", { children: "Ellie's Secret Diary is an excellent dual language PSHE resource for parents, teachers, youth workers and counsellors. The first person account puts readers in the victim's position, making it essential reading from Key Stage 2 onwards. The book includes advice and information for those suffering bullying, as well as useful web links and online resources." })] });
var richText11 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Errol adores gardening and fills his home with beautiful plants, but he dreams of a real outdoor space to grow even more. When he spots an empty rooftop spot, he gets excited\u2014but he soon realises he can't do it all alone. With a bit of help from his neighbours, they turn it into a blooming garden that brings everyone together for a wonderful shared adventure." }), /* @__PURE__ */ e("p", { children: "This heart-warming dual language tale celebrates friendship, teamwork, and the joy of growing things, with colourful illustrations that capture the fun of community spirit. Ideal for young readers and families, it's a lovely pick for sparking talks about helping each other and discovering how small ideas can create big happiness in neighbourhoods everywhere." })] });
var richText12 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Meet Farmer Duck, who's no ordinary duck\u2014he does all the hard work on the farm while the lazy farmer lounges in bed munching sweets and reading the paper. From chopping wood and tending hens to washing dishes and picking apples, the poor duck is worn out until he collapses in a heap. That's when the other farm animals band together with a clever plan to teach the farmer a lesson and make things fair for everyone." }), /* @__PURE__ */ e("p", { children: "This classic dual language picture book is a farmyard favourite, bursting with charming watercolour pictures of lovable characters and a simple, repeating story that's easy for little ones to join in. Great for cosy reads at home or lively group times in school, it gently shares ideas about friendship, hard work, and sticking up for each other in a way that's fun for all ages." })] });
var richText13 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "It's Multicultural Food Day, and children are bringing tasty treats from their cultures to share\u2014think growing veggies, shopping for ingredients, cooking up delights, and enjoying them together. This rhythmic story follows the fun as everyone sees, touches, smells, and tastes fabulous foods from around the world, encouraging even picky eaters to try something new. With a catchy beat and joyful scenes, it's a feast for the senses that gets kids excited about eating well and sharing." }), /* @__PURE__ */ e("p", { children: "Written by Kate Clynes, this vibrant dual language book comes alive with bright pictures and includes extra bits like recipes and activities to try at home or in class. Perfect for families and teachers, it's a wonderful way to explore different cultures, spark chats about healthy food, and create yummy memories through stories and hands-on fun." })] });
var richText14 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "In Aesop's 'The Fox and the Crane', a cheeky fox serves dinner on a flat plate that the crane can't eat from, but soon learns a lesson when the crane flips the trick back. Then, in the Chinese tale 'King of the Forest', a smart fox uses his wits to outsmart a mighty tiger, proving brains beat brawn every time\u2014just like a bit in 'The Gruffalo'! These short stories mix clever twists with timeless morals about fairness and clever thinking." }), /* @__PURE__ */ e("p", { children: "Part of Mantra Lingua's Fables Series, this dual language book pairs fables from different cultures with lively illustrations to introduce young readers to world tales and shared lessons. With teaching notes included, it's ideal for families and classrooms to chat about kindness, right and wrong, and how stories connect us all through fun discussions and activities." })] });
var richText15 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Around the world, kids just like you are having a blast with all sorts of games and sports\u2014from racing camels in Dubai with Faris and his dad, to playing cricket with the whole family in India like Nitesh, or skiing down snowy slopes in Switzerland since he could toddle like Tomas. What\u2019s your favourite outdoor game? This cheerful book invites little ones to discover exciting activities from different places and dream about trying them out too." }), /* @__PURE__ */ e("p", { children: "Part of Mantra Lingua's Our Lives, Our World series, this dual language delight opens eyes to diverse cultures and ways of life with simple words and repeating fun that build chatting skills. Packed with key words and activities, it\u2019s a fab choice for families and schools to explore together, sparking talks about friendship, traditions, and the joy of playing everywhere." })] });
var richText16 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Stop, Goldilocks, go back home\u2014woods aren't safe when you're all alone! But cheeky Goldilocks ignores the friendly mouse's warnings and wanders into the bears' cosy house, tasting porridge, trying chairs, and napping in beds. When the bears return, things get exciting, but this fresh take makes kids wonder: was Goldilocks right to run away, or could she have done something kinder?" }), /* @__PURE__ */ e("p", { children: "Kate Clynes' modern dual language retelling from Mantra Lingua's 'Folktales, Myths and Legends' collection adds clever rhymes and lively pictures to the beloved story, encouraging little readers to think about choices and feelings from both sides. Perfect for family storytime or classroom chats, it's a wonderful way to explore safety, kindness, and what happens next in a fun, thoughtful adventure." })] });
var richText17 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "The fresh snow is as powdery as the sand on the Jamaican beaches and as smooth and white as a sliced yam. The snowballs Mimi and her friends throw are as round and soft as the potatoes in Grandma's Saturday Soup and the frosty clouds are as fluffy as the dumplings that bob in the bubbling broth\u2026. It is winter where Mimi lives but everywhere she looks something reminds her of her grandma's delicious 'Saturday Soup' and her colourful tales of Jamaica." }), /* @__PURE__ */ e("p", { children: "'Grandma's Saturday Soup' is a thoughtful story, in dual language, about belonging to two places at once and learning to love them both. Sally Fraser's lush descriptions of Jamaica make this a delightful addition to the classroom. Young children will be able to memorise the days of the week by following what Mimi gets up to each day. 'Grandma's Saturday Soup' can be used to discuss PSHE and Citizenship topics such as cultural identity with older readers. The subject matter also makes this title particularly useful for coping with homesickness." })] });
var richText18 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Mondi the hen has gone missing and there are hungry lions and sneaky spoonbills about. Join Handa and Akeyo scrambling under bushes, tramping across grasslands and meeting all kinds of creatures in pursuit of Grandma's favourite black hen." }), /* @__PURE__ */ e("p", { children: "Richly narrated and beautifully illustrated, 'Handa's Hen' is a dazzling feast for the senses. Following Handa and Akeyo's exciting journey allows children to develop counting skills as they encounter different groups of animals.\xA0 Younger readers will enjoy counting crickets and spotting starlings, playing memory games and discovering new and exotic animals. Older readers will be able to develop their vocabulary skills through learning about the natural world.The dual language text will allow EAL speakers to access the story and teach their friends to count in their home language.Not a Pen Enable Book." })] });
var richText19 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Handa sets off with a basket full of juicy treats like pineapples, bananas, and mangoes to share with her friend Akeyo in sunny Kenya. But along the way, sneaky animals like a monkey, zebra, and giraffe pinch the fruits one by one, leading to a hilarious mix-up when Handa arrives. This bright tale bursts with yummy surprises and a clever ending that will make little ones giggle." }), /* @__PURE__ */ e("p", { children: "Eileen Browne's classic dual language story shines with rich, colourful pictures that introduce East African animals and fruits, helping kids learn new words and discover different ways of life. Ideal for early readers and sharing at home or school, it's a tasty treat that sparks curiosity about the world and encourages chatting about sharing and surprises." })] });
var richText20 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Deep in the woods, hungry Hansel and Gretel follow a trail of breadcrumbs but stumble upon a scrumptious house made of strawberry tarts, chocolate hearts, caramel windows, and candy canes. It seems like a dream come true\u2014until they meet the tricky witch inside who has sneaky plans. With quick thinking and teamwork, the clever brother and sister find a way to outsmart her and head home safely." }), /* @__PURE__ */ e("p", { children: "This suspenseful dual language retelling from Mantra Lingua's 'Folktales, Myths and Legends' collection brings the Brothers Grimm fairy tale to life with delightful rhymes and enchanting illustrations that keep young readers hooked. Great for reading aloud together, it's a magical pick for families and classes to explore bravery, sticking together, and overcoming tough spots in a thrilling way." })] });
var richText21 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Follow a young girl and her dad as they leave their old home behind and start fresh in a new land, where everything feels strange and a bit scary at first. The girl worries about fitting in, missing her friends, and the differences around her, but her kind dad shares stories, shows her fun new spots, and helps her see the similarities that make it feel like home. By the end, she discovers friendly people, exciting adventures, and that this place is pretty wonderful after all." }), /* @__PURE__ */ e("p", { children: "This heart-warming dual language story celebrates the ups and downs of moving to a new country, perfect for little ones learning about change and building new friendships. With colourful pictures that capture the girl's journey from worry to joy, it's a gentle read for families or schools to share, sparking chats about empathy, immigration, and finding happiness wherever you are." })] });
var richText22 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Head, shoulders, knees and toes, knees and toes\u2014join in the classic nursery rhyme as adorable characters point to each body part with big smiles and bouncy moves. This lively sing-along invites babies and toddlers to wiggle along, touching their heads, shoulders, and more while giggling through the repeating words and catchy tune. It's a joyful way to learn body parts and get moving together." }), /* @__PURE__ */ e("p", { children: "Brimming with cute, eye-catching illustrations, this dual language book is ideal for nurturing a love of reading and music in the tiniest tots. Great for parents and little ones to bond over, it helps build words, coordination, and motor skills through fun play, making it a must-have for playful story times at home or in nursery." })] });
var richText23 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: `One day, young bird Totsuwa spots a red mark on his wing and worries what it means, so his grandfather sends him to wise old bear Yona for advice. As the red spreads across his feathers, Totsuwa embarks on a brave journey through sacred Cherokee spots like Atagahi lake, Kituwah, and Clingman's Dome, meeting helpful friends like clever spider Kananesgi along the way. In this coming-of-age adventure, Totsuwa discovers the "change" is turning him into a proud red cardinal, sacred to the Cherokee people.` }), /* @__PURE__ */ e("p", { children: "Created with the Cherokee Nation, this vibrant dual language retelling by Virginia Hamby and illustrated by Christy Kate Bennett bursts with colourful artwork that brings mythology and heritage to life. Perfect for sharing at home or in class, it includes notes, a map, and free teacher's resources to explore Cherokee culture, identity, and overcoming worries in a magical, uplifting story." })] });
var richText24 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Last night, a curious boy takes the friendly moon for a dreamy stroll through the quiet countryside, where the moon follows like a kite without a string. Together, they wander past rustling trees, sleeping animals, and twinkling stars, discovering the wonders of the night and easing any fears of the dark with gentle magic. Carolyn Curtis' lyrical rhymes weave a whimsical tale that ends with the boy safely home, cherishing his starry friend." }), /* @__PURE__ */ e("p", { children: "Alison Jay's enchanting illustrations light up this calming dual language bedtime story, making it a soothing favourite for little ones and grown-ups to share. Ideal for cosy evenings, it sparks imagination, helps with night-time worries, and invites chats about nature and bravery in a soft, poetic way." })] });
var richText25 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "The beloved King Osiris is murdered by his jealous brother Set and his casket is thrown into the Nile. His grief-stricken queen, Isis, searches all over Egypt to find Osiris' body and set his spirit free. If she succeeds, Osiris will be restored as the rightful ruler of the Land of the Dead for all eternity. If Isis fails, Osiris' spirit will never rest in peace, and his tyrannical brother will destroy Egypt." }), /* @__PURE__ */ e("p", { children: "The legend of Isis and Osiris is a stimulating starting point from which to explore the history, mythology, and culture of Egyptian civilisation. It is particularly useful for studying Egyptian burial rites, as Osiris was the first pharaoh to be mummified. This fascinating account of the lives of two of Ancient Egypt's most popular deities is a fascinating introduction to the Ancient world." })] });
var richText26 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "While Jack rests after his tumble down the hill, plucky Jill steps up to save her family by selling their cow for magic beans that sprout into a giant beanstalk. Climbing high into the clouds, she meets familiar nursery rhyme friends and outsmarts a greedy giant to bring home treasures and keep everyone fed. In this clever spin on the old tale, Jill's bravery and quick wits turn her into the hero who slays the giant and secures a happy ending." }), /* @__PURE__ */ e("p", { children: "Manju Gregory's rhyming dual language retelling from Mantra Lingua's 'Folktales, Myths and Legends' collection mixes fun surprises with lively pictures that delight young readers and flip expectations. Great for families and classrooms, it's a sparkling way to explore courage, fairness, and challenging old ideas about who can be the star of the story." })] });
var richText27 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "A young girl's imagination whisks her away on an exciting adventure through the dazzling world of Islamic art, from grand mosques with swirling patterns to lush gardens and shimmering palaces. As she soars over intricate tiles, golden domes, and beautiful calligraphy, she uncovers the rich history and creativity that make these treasures sparkle. Diana Mayo's stunning illustrations capture the splendour, inviting little explorers to dream big." }), /* @__PURE__ */ e("p", { children: "This captivating dual language book opens doors to Islamic culture and heritage, perfect for curious kids eager to learn about different traditions through vibrant, detailed artwork. Ideal for home or school, it sparks wonder and chats about history, art, and faraway places in a magical, eye-opening way." })] });
var richText28 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Cheetah loved nothing more than running and telling jokes. His best friend, Hippopotamus, laughed at all his jokes even though they weren't very funny. But that wasn't enough for Cheetah. He wanted a friend who could run so he set out to make a new one, leaving Hippopotamus behind\u2026" }), /* @__PURE__ */ e("p", { children: "Find out how Cheetah learns to appreciate what he has and discovers the true value of friendship. Packed with interactive games and activities, Lindsay Camp's 'Keeping up with Cheetah' is an invaluable classroom resource. As well as providing plenty of story time potential, 'Keeping up with Cheetah' is perfect for translation into drama, role-plays and outdoor games." })] });
var richText29 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Head to the farm and discover all the fun sights and sounds, from fluffy chicks cheeping to cows munching hay and tractors rumbling along. With sturdy pages perfect for little hands, this interactive book lets toddlers touch and tap to hear words and noises in English and another language, exploring animals, tools, and farm life up close. The glossary at the back shows pictures with words in both languages, helping tiny learners connect sounds to what they see." }), /* @__PURE__ */ e("p", { children: "This bright, audio-enabled dual language board book is a treat for the youngest explorers, with bold illustrations that make learning new words a playful adventure. Great for parents, teachers, and tots to enjoy together, it's wonderful for building vocabulary and chatting about everyday farm fun." })] });
var richText30 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Stroll down the bustling high street and spot all the exciting shops, from the bakery with yummy smells to the toy store full of treasures and the market buzzing with chatter. This sturdy board book invites little ones to tap around the pages with a talking pen to hear words, sounds, and greetings in two languages, discovering people, items, and activities along the way. A handy glossary at the back pairs images with bilingual text for easy learning." }), /* @__PURE__ */ e("p", { children: "Packed with cheerful illustrations, this dual language delight is audio-ready for extra fun, letting kids record their own voices too. Perfect for families and early learners, it's a lively way to build words, explore community spots, and spark joyful talks about shopping and daily life." })] });
var richText31 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Let's head to the park and see what adventures await, from swinging on swings and chasing butterflies to splashing in puddles and chatting with friends. This big board book for little ones shows colourful scenes of people, animals, and playthings, with simple words that encourage spotting and talking about what's happening. Tap around with a PENpal to hear the story, hidden sounds, and more in two languages for extra excitement." }), /* @__PURE__ */ e("p", { children: "Bold and bright illustrations make this dual language book a hit for 3-4 year olds, helping them recognise words and guess what comes next. Ideal for home or nursery, it's a fab pick for building chatting skills, discovering neighbourhood fun, and enjoying interactive reads that get everyone giggling and exploring." })] });
var richText32 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Li cannot wait for Chinese New Year to come around. There's a lot to be done before Li's family can enjoy the celebrations though: the house must be swept out to brush away any bad luck, there are lanterns to light and decorations to put up, and Li still has to decide which animal of the Chinese zodiac he is going to be in the school assembly. Join Li and his family flying kites and watching fireworks as they welcome in the Chinese New Year." }), /* @__PURE__ */ e("p", { children: "Mantra Lingua's Celebration Series of dual language books\xA0 explores the way people from different cultures celebrate festivals around the world. Packed with recipes, facts, and activities, these beautifully illustrated books offer an invaluable insight into other cultures and traditions. In the classroom, these titles can be used to introduce students to religious festivals and ceremonies that they may not be familiar with. At home, the Celebration Series is perfect for teaching young children about family celebrations." })] });
var richText33 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Lima is really hungry. In the kitchen, there's plenty of food to choose from: a hairy coconut, some shiny samosas and a plateful of sticky sweets\u2026but nothing looks quite as enticing as the shiny red hot chilli pepper her mother told her not to eat. One big bite later and Lima's mouth is bursting with flames and exploding with fireworks." }), /* @__PURE__ */ e("p", { children: "Lima lands herself in a situation familiar to all children who have found themselves unable to resist the temptation of something forbidden. Infused with gentle humour, David Mills' lively tale inspires children to be curious and open minded about the world around them. Useful for exploring the five senses, 'Lima's Red Hot Chilli Pepper' introduces readers to different foods and encourages creative problem solving skills. Lima's family's trial-and-error experiments make a fantastic addition to any science lesson. This title can also be used for developing role-plays and building more complex vocabulary." })] });
var richText34 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "In Aesop's 'The Lion and the Mouse', a lion spares the life of a little mouse and soon learns that size is not everything. The proud lion in the Tibetan fable 'The Hare's Revenge' learns his lesson the hard way when the hare decides to put a stop to his bullying ways." }), /* @__PURE__ */ e("p", { children: "Mantra Lingua's Fables series of dual language books offers young readers a captivating introduction to the fable tradition. Pairing Aesop's fables with those from other cultures, this series introduces readers to world literature and enables them to pick out moral themes common to many cultures. The fables have been chosen to provide ample scope for discussing moral and ethical questions and Citizenship topics. These titles also include teaching notes and can be used for a wide range of cross-curricular activities, making these collections a wonderful addition to any classroom." })] });
var richText35 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Honk, honk, geese call. Swish, swish, leaves fall. Whoosh, whoosh, hats fly. Whoo, whoo, owls cry. Dive into the wonders of the seasons with this rhythmic tale that captures the lively sights and sounds of nature, from the buzz of summer bees and sizzling sun to the crunch of autumn leaves, the crackle of winter snow, and the splash of spring rain. Phillis Gershator's gentle rhymes guide young listeners through a year of outdoor magic, sparking joy with every page." }), /* @__PURE__ */ e("p", { children: "Alison Jay's breathtaking illustrations bring each season to vivid life in this delightful dual language book, perfect for little ones discovering phonics and the world around them. Ideal for cosy family reads or classroom fun, it encourages chats about weather, animals, and nature while building early language skills in a playful, captivating way." })] });
var richText36 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Mamy Wata, the graceful queen of all waters, swims peacefully in a big river until she hears tales of a scary monster terrifying nearby villages. Venturing into his cave, she discovers not a beast, but a sad, frightened man under a wicked spell, and uses her kindness and cleverness to help him break free and find happiness again. Bursting with warmth and adventure, this story celebrates compassion and the power of understanding." }), /* @__PURE__ */ e("p", { children: "V\xE9ronique Tadjo's award-winning dual language tale, honoured by UNICEF and listed among the 100 Best African Books of the Century, shines with explosive colours that bring African culture alive on every page. Perfect for families and schools, it's a joyful way to explore themes of empathy, bravery, and traditions while delighting young readers with its magical river world." })] });
var richText37 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "When Marek and Alice celebrate Christmas in Poland with their grandparents they discover all sorts of Polish traditions they never knew about. Join in the festive fun and discover why on Christmas Eve in Babcia's house there is a pile of hay under the table, a fish swimming in the bath and an empty place set at dinner." }), /* @__PURE__ */ e("p", { children: "Mantra Lingua's Celebration Series of dual language books explores the way people from different cultures celebrate festivals around the world. Packed with recipes, facts, and activities, these beautifully illustrated books offer an invaluable insight into other cultures and traditions. In the classroom, these titles can be used to introduce students to religious festivals and ceremonies that they may not be familiar with. At home, the Celebration Series is perfect for teaching young children about family celebrations." })] });
var richText38 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "At a cheerful class party, Mei Ling suddenly gets the hiccups that just won't stop, no matter how hard she tries. Her kind classmates chime in with all sorts of fun remedies they've learned from their families\u2014like holding your nose, looking upside down, or spinning around\u2014each one sharing a special trick from their own culture. In this bubbly tale by David Mills, Mei Ling discovers a clever way to quiet her hiccups while celebrating the diverse ways friends help each other." }), /* @__PURE__ */ e("p", { children: "This light-hearted dual language story bursts with colourful classroom scenes, making it a wonderful pick for little ones to giggle over customs, traditions, and superstitions from around the world. Great for home or school, it sparks talks about friendship, sharing ideas, and trying new things in a fun, inclusive adventure." })] });
var richText39 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "In the beautiful autumnal Highlands of Scotland, old horse Mungo feels lonely with nothing to look forward to, until a series of furry friends\u2014like a squirrel, rabbit, and more\u2014start sharing his meals and bringing cheer to his days. As the seasons shift to winter, Mungo moves to his cosy stables, and his loyal pals team up on a clever plan to stay by his side through the snow. Gill Aitchison's heart-warming tale follows Mungo's journey from solitude to joyful companionship." }), /* @__PURE__ */ e("p", { children: "Jill Newton's stunning illustrations immerse young readers in the scenic Scottish landscape in this engaging dual language book, perfect for little ones and older children alike. With rhythmic repetition for confident reading and points for chatting about friendship and change, it's ideal for families or classrooms to build language skills and create cosy story moments." })] });
var richText40 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Dive into a world of words with this colourful picture dictionary featuring over 650 everyday terms sorted into 34 fun themes, like family, animals, food, toys, and more\u2014from wild creatures to classroom bits. Pair it with a PENpal for magical audio: touch a word to hear a native speaker say it in English or your chosen language, and even record your own voice to practise pronunciation or make sentences." }), /* @__PURE__ */ e("p", { children: "This interactive dual language resource is a treasure for new learners, EAL children, or anyone building vocabulary at home or school. With themes covering everything from colours and numbers to sports and space, it's a versatile tool that turns learning into play, helping kids connect sounds, pictures, and words with ease." })] });
var richText41 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Nita is knocked down by a car and breaks her leg. She is taken to hospital where she is very brave. The doctors and nurses look after her and help her to walk on crutches until her leg mends. Find out what happens during Nita's stay in hospital and how the doctors and nurses make her better." }), /* @__PURE__ */ e("p", { children: "Mantra Lingua's First Experience series of dual language books is a collection designed to help young readers understand what to expect from unfamiliar and potentially daunting scenarios such as having an operation or starting a new school. The titles in this series explore how we might feel faced with a new situation and how we can cope with it. Simple narratives and warm illustrations make these titles an accessible and reassuring way to relieve anxiety and dispel phobias and fears." })] });
var richText42 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Little Red Riding Hood heads into the woods once more, this time with a basket of cookies for her dad's lunch, but along the way, she bumps into hungry friends like the Three Bears with empty bowls and the Three Billy Goats Gruff with rumbling tummies. As she kindly shares her treats\u2014counting down from 10 to 1\u2014a sneaky grey tail and sharp teeth lurk nearby, leading to a chase where Red must outwit the Big Bad Wolf to save the day and deliver what's left." }), /* @__PURE__ */ e("p", { children: "Kate Clynes' clever dual language retelling from Mantra Lingua's 'Folktales, Myths and Legends' collection mixes fairy tale favourites with bouncy rhymes and lively illustrations that keep kids hooked. Brilliant for practising counting and comparing stories, it's a fab choice for families and classes to explore bravery, sharing, and numeracy in a whimsical adventure." })] });
var richText43 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Zeus bestows upon Pandora the gifts of the gods and sends her to earth where Epimetheus falls in love with her. On their wedding day Zeus gives the couple a beautiful box which must never be opened. When Pandora, unable to contain her curiosity, cannot resist opening the forbidden box, she unleashes suffering into the world." }), /* @__PURE__ */ e("p", { children: "This famous Greek myth tells the story of mankind's fall and the origins of hope. Henriette Barkow's simple retelling of the myth of Pandora's Box brings Greek mythology to life for young readers. 'Pandora's Box' encompasses many of Ancient Greece's most renowned myths and legends and is a captivating introduction to studying ancient mythology. For older readers, this adaptation also provides useful points of comparison with creation myths and religious teachings from other cultures." })] });
var richText44 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: `Pinocchio, the little wooden puppet who dreams of being a real boy, heads off to school where he's teased by classmates until they decide to "teach" him how to be "real" by doing naughty things like skipping lessons and causing mischief. But when their pranks go too far, Pinocchio starts thinking for himself, learning to say no and take responsibility for his choices, turning his journey into one of growth and true friendship.` }), /* @__PURE__ */ e("p", { children: "Magda Brol's bold illustrations breathe fresh life into this classic dual language tale, re-told with heart by a multilingual advocate in her debut picture book. Perfect for young readers exploring right and wrong, it's a thoughtful pick for homes and schools to chat about peer pressure, honesty, and being yourself in a vibrant, empowering way." })] });
var richText45 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Ssh! Listen. What\u2019s that noise? What can we hear when we\u2019re really, really quiet? Follow a little toddler through a busy day that winds down to bedtime, tuning into the everyday sounds around home\u2014from the chatter and clatter of dinner time to the gentle hush of Daddy\u2019s voice reading a story. As the noises fade into peaceful quiet, this sensory adventure helps young ones notice the world of sounds that shape their routines." }), /* @__PURE__ */ e("p", { children: "Kate Alizadeh\u2019s enchanting dual language picture book invites families to explore auditory clues and daily rhythms, making it especially supportive for children who are blind or partially sighted. With inclusive illustrations and TalkingPEN-enabled audio in English and another language, it\u2019s a perfect tool for building vocabulary, encouraging listening skills, and sharing cosy moments at home or in nursery." })] });
var richText46 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Meet RAAG, a lively zebra whose big feelings bubble over into anger, turning his black stripes bright red every time he loses his cool. Unhappy with his fiery outbursts, RAAG turns to his caring best friend Rufus for help, learning step by step how to calm down and handle his temper with clever tricks and kind support. Through fun adventures on the savannah, RAAG discovers that managing emotions makes life happier for everyone." }), /* @__PURE__ */ e("p", { children: "This uplifting dual language story from Mantra Lingua shines a light on feelings and self-control, with vibrant illustrations that capture the excitement of learning to stay calm. TalkingPEN-enabled for audio in English and another language, it\u2019s ideal for families and classrooms to spark chats about anger, friendship, and positive ways to cope, helping little ones build emotional skills." })] });
var richText47 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Rafa is a chatterbox who talks non-stop about everything, especially his excitement for starting big school\u2014he babbles all the way there on the big day. But once he arrives, the words dry up; he\u2019s not sad, he loves his new friends, building blocks, and drawing, yet he just can\u2019t speak a peep. Join Rafa as he navigates his quiet first day, until something special finally brings his voice bursting back." }), /* @__PURE__ */ e("p", { children: "This gentle dual language tale about selective mutism and new beginnings encourages empathy and understanding, with warm illustrations that show the joys of school life. Perfect for little ones facing changes, it\u2019s a reassuring read for families and teachers to discuss feelings, bravery, and finding your voice in a supportive way." })] });
var richText48 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "In a mystical forest from an ancient Romani folktale, young Rani meets a handsome prince who falls in love with her and dreams of marriage, but the evil witch queen Morgana has wicked schemes to keep them apart. Facing trials of good versus evil, heartbreak and reunion, poverty and riches, Rani must summon her courage to outwit the sorceress and claim her happy ending. With twists of magic and bravery, this enchanting story weaves a spell of adventure and triumph." }), /* @__PURE__ */ e("p", { children: "Raymond Slavnic\u2019s atmospheric retelling in dual language comes alive with Valentin Olshvang\u2019s dreamlike collages blending photos, textures, and paints for a dramatic, layered world. Great for inspiring creativity, it invites kids to explore themes of resilience and folklore while crafting their own collages, making it a captivating pick for family reads or classroom discussions." })] });
var richText49 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Row, row, row your boat, gently down the stream\u2014join merry animals on a splashy adventure full of surprises, from spotting tigers to dreaming sweetly. This timeless nursery rhyme invites tiny tots to sing along with actions, clapping, rocking, and waving as they float through the fun verses. With bouncy rhythm and interactive fun, it\u2019s a joyful ride that ends in giggles and cuddles." }), /* @__PURE__ */ e("p", { children: "Brimming with cute, colourful illustrations, this dual language sing-along book nurtures a love of reading and music in babies and toddlers. Ideal for parents and little ones to share, it boosts words, coordination, and motor skills through playful rhymes, creating hours of happiness at home or in nursery." })] });
var richText50 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "When Sahir loses a tooth, he puts it under his pillow and by the time he wakes up the tooth fairy has replaced it with a shiny coin. Before Sahir can spend it though, he needs to go to the dentist. Find out what it's like to have a model made of your teeth and what the dentist can do to help Sahir's sister when she gets a hole in her tooth." }), /* @__PURE__ */ e("p", { children: "Mantra Lingua's First Experience series of dual language books is a collection designed to help young readers understand what to expect from unfamiliar and potentially daunting scenarios such as having an operation or starting a new school. The titles in this series explore how we might feel faced with a new situation and how we can cope with it. Simple narratives and warm illustrations make these titles an accessible and reassuring way to relieve anxiety and dispel phobias and fears." })] });
var richText51 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "The first sighting of the new moon marks the beginning of Eid and a day of celebration for Samira and her family. The Ramadan fast is over and now it is time for prayers and presents. Join Samira's family as they celebrate this Islamic festival with Muslims from all around the world." }), /* @__PURE__ */ e("p", { children: "Mantra Lingua's Celebration Series of dual language books explores the way people from different cultures celebrate festivals around the world. Packed with recipes, facts, and activities, these beautifully illustrated books offer an invaluable insight into other cultures and traditions. In the classroom, these titles can be used to introduce students to religious festivals and ceremonies that they may not be familiar with. At home, the Celebration Series is perfect for teaching young children about family celebrations." })] });
var richText52 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "The jungle buzzes with excitement as animals gear up for Sports Day, leaping, pouncing, and juggling in thrilling races\u2014but slow Sloth feels left out, teased by cheeky Monkey for being too sluggish. When disaster strikes and the event is in jeopardy, Sloth\u2019s unique talents save the day, teaching everyone that every creature has a special role to play. Blending fun facts with fable, this lively tale celebrates inclusion and the power of teamwork." }), /* @__PURE__ */ e("p", { children: "Jill Newton\u2019s exuberant dual language story bursts with vibrant jungle scenes and animal antics, making it a hit for exploring morals like kindness and collaboration. Perfect for group reads or activities, it encourages kids to try team challenges, discuss contributions, and learn that true winners value everyone\u2019s strengths." })] });
var richText53 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Most days, little Cori the squirrel monkey is full of playful energy, swinging through the South American rainforest with glee\u2014but sometimes overwhelming feelings take over, leaving him in distress that no one can calm. When his wise mum tries slow, meditative breathing, guided by tiny leaf ants, they find a peaceful spot where Cori learns to quiet his mind and regain control. This relatable story shows how mindfulness can turn big emotions into moments of calm." }), /* @__PURE__ */ e("p", { children: "Part of Mantra Lingua\u2019s IFeel series on feelings, Elizabeth Alvarez Alfaro\u2019s dual language book features sparkling illustrations by Jesus Gaban and helpful teacher notes for activities on emotions, writing, and vocabulary. TalkingPEN-enabled for bilingual audio, it\u2019s a thoughtful resource for families and schools to discuss coping strategies and support children through everyday ups and downs." })] });
var richText54 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Sunita and her classmates are buzzing with excitement as they board the school bus for a trip to the zoo, eager to see elephants spraying water, sea lions splashing, goats munching, penguins waddling, monkeys swinging, parrots chattering, and even ride a camel. But amid the wonders, a little mishap adds a twist to their day\u2014what could possibly go wrong on this animal-packed outing? Join Sunita for a whirlwind of discovery and fun that turns into an unforgettable adventure." }), /* @__PURE__ */ e("p", { children: "Part of Mantra Lingua\u2019s charming Sunita series, this dual language book captures the joy of school trips and new experiences with warm, detailed illustrations. PENpal-enabled for audio in English and another language, it\u2019s a delightful choice for young readers to explore animals, friendship, and curiosity at home or in class." })] });
var richText55 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Sunita feels lonely playing by herself while her brother cycles with his pal and her sister bounces a ball with a friend\u2014even the birds ignore her invitations to join in. When her sister\u2019s ball smashes a neighbour\u2019s window, Sunita and Dad go to apologise, discovering a kind elderly couple whose granddaughter Sally visits from afar. Soon, Sally arrives, sparking wonderful new friendships that fill Sunita\u2019s days with laughter and play." }), /* @__PURE__ */ e("p", { children: "This heart-warming dual language story from Mantra Lingua\u2019s Sunita series celebrates neighbourly kindness and building bonds across generations. With cosy illustrations and PENpal audio support, it\u2019s perfect for little ones learning about empathy, community, and the magic of making friends in unexpected ways." })] });
var richText56 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Sunita loves hearing about Halloween at school and rushes home to tell Mum, who agrees to throw a party with friends, complete with sticky doughnut games, apple bobbing, witch hats, and glowing lanterns. Amid the spooky fun and treats, Sunita discovers there\u2019s no need for ghosts when the day is filled with family joy and laughter. This festive tale blends excitement with cultural warmth for a truly special celebration." }), /* @__PURE__ */ e("p", { children: "Part of Mantra Lingua\u2019s engaging Sunita series exploring everyday adventures, this dual language book highlights themes of traditions and togetherness with vibrant, pencil-drawn illustrations. PENpal-enabled for bilingual listening, it\u2019s an ideal read for families to share holiday cheer and chat about blending cultures in a light-hearted way." })] });
var richText57 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Mia and Kai don't look like their mums. When Mia goes out with her mum, people assume that they are not related. If ever Mia, Kai and their parents go out for the day, total chaos ensues. One day Mia and Kai decide that enough is enough and they come up with a way to put a stop to the confusion." }), /* @__PURE__ */ e("p", { children: "Written in the first person, Mia relates her experience of being a child of mixed heritage. Find out how she and Kai overcome being judged by the colour of their skin. 'That's my Mum' in dual language is an invaluable starting point for discussing Citizenship and PSHE topics including prejudice, discrimination and cultural identity." })] });
var richText58 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "In a dry, thirsty land, Buffalo spots the moon looking like a giant delicious biscuit and dreams of eating it, but soon Lion and other animals join in, arguing and fighting over who gets the tasty prize. As greedy Vulture circles overhead waiting for scraps, wise Squirrel points out that chasing illusions won't help, and instead leads the group on a journey to find real green lands and water. This clever allegory on migration shows how working together beats squabbling over tricks of the mind, with a cyclical twist that leaves room for more adventures." }), /* @__PURE__ */ e("p", { children: "Enebor Attard's rhythmic dual language retelling, illustrated by Jes\xFAs Gab\xE1n's brilliant artwork, is packed with repetition and growing words to build confidence in young readers new to English. Perfect for families and classrooms exploring themes of sharing, illusions, and teamwork, it's a thoughtful pick that links to real-world events like cooperation in tough times, encouraging chats about hopes and helping each other." })] });
var richText59 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: `When a lame donkey, bespectacled dog, elderly cat, and worn-out cockerel are cast aside by their owners, they band together to form a quirky travelling music group heading to Bremen for a fresh start. Along the way, they stumble upon a robbers' hideout and use their clever noises\u2014hee-hawing, woofing, meowing, and cock-a-doodle-dooing\u2014to scare the thieves away and claim a cosy new home. This humorous German fairy tale celebrates reinvention and friendship, with the animals discovering that their "music" brings unexpected success.` }), /* @__PURE__ */ e("p", { children: "Henriette Barkow's lively dual language adaptation from Mantra Lingua's 'Folktales, Myths and Legends' collection bursts with delightful rhymes and vibrant illustrations that charm kids and adults. Ideal for discussing respect for elders, teamwork, and inclusiveness, it's a fun resource for classrooms or home reads to explore moral tales and spark creative storytelling from around the world." })] });
var richText60 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "King Lir's three beloved children are turned into graceful swans by their jealous stepmother queen, cursed to wander the stormy North Sea for nine hundred lonely years. As they endure icy waves and wild winds, the siblings cling to hope and each other, singing haunting songs that echo their sorrow until a chance for freedom arises. Dawn Casey's beautiful retelling of this classic Irish myth weaves magic, tragedy, and redemption into a timeless tale of family bonds and resilience." }), /* @__PURE__ */ e("p", { children: "This enchanting dual language book introduces young readers to Celtic mythology with poetic language and captivating illustrations that bring the legend alive. Perfect for families and schools to discuss perseverance, jealousy, and creative writing, it serves as a gentle gateway to world folklore and encourages imaginative exploration of ancient stories." })] });
var richText61 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Young Chun Li catches a golden fish and kindly sets it free, earning a magical pearl that brings his family wealth and good luck at first. But as the pearl's power grows wildly out of control, turning everything it touches into riches, Chun Li must find a way to restore balance before disaster strikes. Inspired by how the twenty-four lakes of the river Min got their name, this folk tale highlights the rewards of compassion and the dangers of unchecked greed." }), /* @__PURE__ */ e("p", { children: "Manju Gregory's sensitive dual language retelling from Mantra Lingua's World Tales collection features Gua Le's stunning Chinese brush art that immerses readers in Eastern culture. Great for chatting about kindness, fortune, and moral choices with Key Stage 1 and 2 children, it's a vibrant pick for homes or classrooms to discover global traditions through rhymes and clever twists." })] });
var richText62 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "A kind but penniless shoemaker and his wife are puzzled when beautiful shoes appear overnight on their workbench, stitched with perfect care while they sleep. Night after night, tiny mysterious helpers snip, stitch, and swoosh to create gleaming pairs that sell quickly, bringing the couple good fortune. When they finally spy the hardworking elves and repay their kindness, the story unfolds with warmth and wonder in this timeless Grimm fairy tale." }), /* @__PURE__ */ e("p", { children: "Henriette Barkow's heart-warming dual language version from Mantra Lingua's 'Folktales, Myths and Legends' collection sparkles with lively rhymes and enchanting illustrations that delight early readers. Ideal for exploring themes of generosity, charity, and helping others, it's a charming resource for families and teachers to inspire discussions on fairness and gratitude in a magical way." })] });
var richText63 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "A plucky, over-confident boy takes a tumble on his bicycle and wakes up in a strange, ancient land filled with mysterious scripts and symbols, from Egyptian hieroglyphics to modern comic texts. Guided by a wise man, he embarks on an adventure through the evolution of writing, discovering how scripts tie to culture, power, and society while racing to find his way home. This graphic novel-style tale blends excitement with learning, turning a simple fall into a thrilling journey of discovery." }), /* @__PURE__ */ e("p", { children: "Aimed at ages 9 to 13 and new to English readers, this dual language book features Alex Hiett's dramatic illustrations that bring the adventure to life. Perfect for reluctant readers and classrooms, it's a clever way to explore language history, multiculturalism, and communication, encouraging chats about how words shape our world." })] });
var richText64 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Miss Honeywood's class plants a vegetable garden, but they're amazed when one turnip grows taller than a giraffe and wider than an elephant. Pulling it out seems impossible until everyone\u2014from tiny mice to the whole school\u2014joins forces with a mighty heave-ho to harvest the giant veggie. This modern spin on a Russian fairy tale shows how little helpers can solve big problems through cooperation and clever thinking." }), /* @__PURE__ */ e("p", { children: "Henriette Barkow's humorous dual language retelling from Mantra Lingua's 'Folktales, Myths and Legends' collection glows with vivid illustrations that capture the fun of growing things. Great for young children to learn about plants, seasons, and the natural world, it's an engaging pick for homes or schools to discuss teamwork and sharing in a light-hearted adventure." })] });
var richText65 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "In Aesop's fable, a greedy farmer discovers his goose lays golden eggs and gets rich, but his impatience leads him to kill the bird, losing everything in a rush for more. Paired with the Buddhist tale of a talkative tortoise carried by geese on a stick, who falls after opening his mouth despite warnings, these stories warn against greed and the value of silence. Together, they blend timeless wisdom with clever animal antics for thoughtful fun." }), /* @__PURE__ */ e("p", { children: "Part of Mantra Lingua's Fables series, this dual language book pairs global tales with lively illustrations to highlight shared morals across cultures. Including teaching notes for activities, it's ideal for classrooms and families to explore ethics, right and wrong, and citizenship topics through engaging discussions and cross-curricular play." })] });
var richText66 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Little Red Hen finds some wheat grains and asks her lazy friends\u2014the cat, dog, and goose\u2014for help planting, growing, harvesting, milling, and baking them into bread, but they're always too busy lounging. When the warm, fresh loaf is ready, the others eagerly want a share, but Little Red Hen teaches a gentle lesson about earning rewards through effort. This subtle retelling of a Russian classic emphasizes contribution and fairness." }), /* @__PURE__ */ e("p", { children: "Henriette Barkow's accessible dual language adaptation from Mantra Lingua's 'Folktales, Myths and Legends' collection features charming illustrations and rhymes that make it a classroom must-have. Perfect for early readers to discuss hard work, teamwork, and helping others, it's a delightful way to introduce moral tales and reap the joys of storytelling traditions." })] });
var richText67 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "The town of Hamelin is plagued by rats until a mysterious piper arrives, charming the pests away with his magical flute tunes. But when the ungrateful townspeople refuse to pay him, the piper plays a haunting melody that leads their children dancing out of town in shocking revenge. Henriette Barkow's thoughtful retelling explores promises, fairness, and the consequences of broken trust in this German folktale." }), /* @__PURE__ */ e("p", { children: "This gripping dual language story from Mantra Lingua's 'Folktales, Myths and Legends' collection captivates with delightful rhymes and vibrant pictures that keep young readers engaged. Ideal for sparking chats about honesty, strangers, and responsibility with Key Stage 1 and 2 children, it's a versatile pick for homes or schools to delve into moral themes and global legends." })] });
var richText68 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "A lively little girl borrows her mum's swirling hijab for playful adventures, transforming it into a billowing sail on a pirate ship, a cosy fort to hide in, a nomad's pack for desert treks, or a warrior queen's cloak for battles. Through her imagination, she discovers endless possibilities, but learns its true purpose is covering her mum as part of her faith. This endearing tale highlights creativity and cultural pride." }), /* @__PURE__ */ e("p", { children: "Na'ima bint Robert's charming dual language book shines with warm illustrations that capture the joy of pretend play. Perfect for exploring Muslim traditions, multiculturalism, and diversity, it's a sensitive resource for families and classrooms to discuss faith, identity, and respecting differences in a fun, inclusive way." })] });
var richText69 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Three hungry billy goats want to cross a bridge to munch juicy grass, but a grumpy troll guards it, threatening to gobble them up. The clever smaller goats promise a bigger brother is coming, outsmarting the troll until the biggest goat charges with a mighty butt to send him flying. Set against fluffy clouds and green hills, this Norwegian folktale brims with bravery and quick wits." }), /* @__PURE__ */ e("p", { children: "Henriette Barkow's delightful dual language retelling from Mantra Lingua's 'Folktales, Myths and Legends' collection features enchanting rhymes and lively illustrations that enchant young readers. Great for weighing choices and outcomes, like bravery versus running away, it's a whimsical choice for homes or schools to chat about problem-solving and whether all tales teach lessons." })] });
var richText70 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "One sunny morning, a tiny hungry caterpillar hatches from an egg and munches through apples, pears, plums, and more yummy foods all week, even indulging in treats like cake and cheese that give him a tummy ache. After a big feast, he spins a cocoon and emerges as a beautiful butterfly, teaching about growth and change. Eric Carle's timeless story counts days, fruits, and transformations with simple charm." }), /* @__PURE__ */ e("p", { children: "This bestselling dual language favourite bursts with bold, colourful collages that help little ones learn numbers, days of the week, and healthy eating. Ideal for cosy family reads or classroom fun, it's a versatile pick to build vocabulary, spark curiosity about nature, and celebrate the wonder of becoming something new." })] });
var richText71 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "When Li's first tooth wobbles and falls out, he's excited but unsure what to do next\u2014his friends share traditions like burying it for a new one like Kofi, leaving it for the tooth fairy like Joey, or tossing it in a river for luck like Salma. Li chooses his own special way, celebrating the milestone with joy. David Mills' story explores global customs around baby teeth in a fun, relatable way." }), /* @__PURE__ */ e("p", { children: "This cheerful dual language book delights with illustrations of diverse friends and includes ideas for chatting about traditions and superstitions. Perfect for young children facing wobbly teeth, it's a wonderful resource for families and schools to discuss communities, sharing, and growing up together." })] });
var richText72 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Tom and Sofia are ready for their first day at school with shiny uniforms and packed bags, but Tom feels a bit nervous about getting lost or making friends, while bubbly Sofia can't wait to join in like her big sister. As they explore classrooms, play games, and meet new pals, both discover the fun of learning and settle in happily. This sweet tale captures the mix of excitement and jitters on a big new adventure." }), /* @__PURE__ */ e("p", { children: "Part of Mantra Lingua's First Experience series, this dual language book uses warm illustrations to ease worries about starting school from different viewpoints. Ideal for preparing little ones for changes, it's a reassuring read for homes or nurseries to talk about feelings, coping, and the joys of new beginnings." })] });
var richText73 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Take a stroll through a bustling city and spot everyday wonders, from busy markets and zooming buses to friendly faces in parks and twinkling shop windows\u2014what do you see, hear, or smell along the way? This interactive book invites young explorers to add their own stories to the vibrant scenes, pointing out hidden details and sharing discoveries. With gorgeous, detailed pictures, it's a playful journey that turns a simple walk into endless fun." }), /* @__PURE__ */ e("p", { children: "Designed to encourage talk during shared reading, this dual language delight sparks curiosity about urban life and senses with bright illustrations that engage little readers. Perfect for families or classrooms, it's a creative tool to build chatting skills, explore neighbourhoods, and inspire imaginative tales together." })] });
var richText74 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: `A brave young explorer ventures through the jungle, desert, mountains, and sea, spotting fierce animals like roaring lions, slithering snakes, and splashing whales that seem to chase after. With catchy rhymes like "Walking through the jungle, what do you see? I think I see a tiger, chasing after me," the adventure builds excitement until a safe return home for tea. Debbie Harter's vibrant take on the classic chant is full of exotic surprises.` }), /* @__PURE__ */ e("p", { children: "This lively dual language book echoes Eric Carle's style with colourful crowds of animals and repeating sounds that make it ideal for group sing-alongs. Great for early readers to learn creature noises and habitats, it's a thrilling pick for homes or circle time to boost vocabulary and imagination in a rhythmic romp." })] });
var richText75 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: `A cheerful family sets off on a bear hunt through long grass, a splashy river, squelchy mud, and a swirling snowstorm, chanting "We're going on a bear hunt, we're going to catch a big one\u2014what a beautiful day! We're not scared." With onomatopoeic sounds like swishy swashy and squelch squerch, they brave obstacles until they find a real bear and race home giggling. Michael Rosen's rollicking adaptation of the camp song is a bouncy, repeatable delight.` }), /* @__PURE__ */ e("p", { children: "This classic dual language picture book bursts with Helen Oxenbury's enchanting illustrations that capture the thrill and cosiness of adventure. Ideal for acting out in gardens or classrooms, it builds language skills with adjectives, prepositions, and sounds, making it a must for families to explore bravery, nature, and family fun." })] });
var richText76 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "When baby brother Tariq arrives, his classmates share how their families celebrate newborns\u2014from washing with holy water, whispering prayers, or giving sweet tastes to mark the start of life. Exploring senses like touch, smell, and sound, this story highlights diverse traditions around births with warmth and joy. It's a beautiful peek into global ways of saying hello to a little one." }), /* @__PURE__ */ e("p", { children: "This sensitive dual language book, TalkingPEN-enabled for audio, features charming illustrations that invite chats about religious rituals, multiculturalism, and family customs. Perfect for welcoming new siblings or classroom discussions on diversity and the five senses, it's an inclusive treasure for young readers to celebrate life's beginnings." })] });
var richText77 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Impatient Jaya can't wait for her grandmother Nani's cherry pie, but wise Nani teaches her to slow down through seasonal activities like pruning trees, planting bulbs, and watching nature bloom. As time passes and surprises unfold, Jaya learns that good things come to those who wait, turning frustration into appreciation for the rewards. Jesse Kaur's partly autobiographical tale captures the bond between generations with gentle wisdom." }), /* @__PURE__ */ e("p", { children: "Fiona Rose's chalky illustrations beautifully show changing seasons in this dual language book from Mantra Lingua's IFeel collection on emotions. Perfect for little ones to explore patience and mindfulness, it's a cosy read for families or schools to discuss slowing down, nature's gifts, and the joy of waiting together." })] });
var richText78 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "In ancient China, kind Yeh-hsien befriends a magical red fish that grants her wish for beautiful clothes to attend the Spring Festival, where she dazzles everyone but loses a tiny golden slipper. When the king searches for the mysterious girl who fits the shoe, Yeh-hsien's life transforms from hardship to happiness, outwitting her cruel stepmother. This oldest known Cinderella story sparkles with wonder and justice." }), /* @__PURE__ */ e("p", { children: "Dawn Casey's dual language retelling from Mantra Lingua's World Tales collection features lively illustrations and clever twists that highlight cultural variations in fairy tales. Great for comparing global legends and discussing themes like kindness and perseverance, it's an enchanting choice for young readers to discover folklore traditions and moral lessons." })] });
var richText79 = /* @__PURE__ */ t(a.Fragment, { children: [/* @__PURE__ */ e("p", { children: "Have you ever eaten sushi and noodles? How about rice and peas with goat curry? Meet eleven children from around the world and find out about their favourite foods. Discover how Polish bigos are made and how Abeba's family serve injera, then try making some at home! What is your favourite food and where does it come from?" }), /* @__PURE__ */ e("p", { children: "Mantra Lingua's Our Lives, Our World series of dual language books helps young readers to widen their horizons and to develop a tolerant worldwide perspective by introducing them to diverse cultures, traditions and lifestyles. Simple, repetitive sentence structures and basic vocabulary make these titles useful for building verbal communication skills.\xA0 An essential cross-curricular resource for teaching EAL, Citizenship and PSHE, each title in this series includes a key words and activities section for use in the classroom." })] });
